import React, { useState } from 'react';
import './Contact.css';

const API = process.env.REACT_APP_API_URL || 'http://localhost:5000';

const SUBJECTS = ['Khiếu nại / Phản ánh', 'Yêu cầu hỗ trợ', 'Quên đồ trên xe', 'Góp ý dịch vụ', 'Khác'];

export default function Contact({ showToast }) {
  const [form, setForm] = useState({ name: '', phone: '', email: '', subject: SUBJECTS[0], message: '' });
  const [loading, setLoading] = useState(false);
  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async e => {
    e.preventDefault();
    if (!form.name || !form.message) return showToast('Vui lòng nhập tên và nội dung', 'error');
    setLoading(true);
    try {
      const res = await fetch(`${API}/api/contact`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(form) });
      const data = await res.json();
      showToast(data.message, data.success ? 'success' : 'error');
      if (data.success) setForm({ name: '', phone: '', email: '', subject: SUBJECTS[0], message: '' });
    } catch { showToast('Lỗi kết nối. Vui lòng thử lại.', 'error'); }
    finally { setLoading(false); }
  };

  return (
    <section id="contact" className="section section--alt">
      <div className="container">
        <div className="section-label">Liên hệ</div>
        <h2 className="section-title">Hỗ trợ & Khiếu nại</h2>
        <p className="section-sub" style={{ marginBottom: 48 }}>Gửi yêu cầu hoặc phản hồi — chúng tôi trả lời trong 24 giờ làm việc.</p>
        <div className="contact__inner">
          <div className="contact__info">
            <div className="contact__info-block">
              <h4>📞 Tổng đài đặt xe</h4>
              <a href="tel:0329537532" className="contact__hotline">0329.537.5324</a>
              <a href="tel:0978202606" className="contact__hotline">0978.202.606</a>
              <p>Hoạt động 24/7 · </p>
            </div>
            <div className="contact__info-block">
              <h4>📞 Tổng đài khiếu nại</h4>
<a href="tel:0329537532" className="contact__hotline">0329.537.5324</a>
              <a href="tel:0978202606" className="contact__hotline">0978.202.606</a>              <p>Thứ 2 – Thứ 7 · 7:00 – 21:00</p>
            </div>
            <div className="contact__info-block">
              <h4>✉️ Email</h4>
              <a >đang cập nhật</a>
            </div>
            <div className="contact__info-block">
              <h4>📍 Văn phòng chính</h4>
              <p> đang cập nhật </p>
            </div>
            <div className="contact__map-placeholder">
              <div className="contact__map-text">🗺️ Bản đồ Google Maps<br /><small>(Đang cập nhật)</small></div>
            </div>
          </div>
          <div className="contact__form card">
            <h3 style={{ fontFamily: 'var(--font-display)', fontWeight: 700, color: 'var(--navy)', marginBottom: 20 }}>Gửi yêu cầu hỗ trợ</h3>
            <form onSubmit={handleSubmit} noValidate>
              <div className="form-row">
                <div className="form-group"><label>Họ tên *</label><input placeholder="Nguyễn Văn A" value={form.name} onChange={e => set('name', e.target.value)} /></div>
                <div className="form-group"><label>Số điện thoại</label><input type="tel" placeholder="09xx xxx xxx" value={form.phone} onChange={e => set('phone', e.target.value)} /></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Email</label><input type="email" placeholder="email@example.com" value={form.email} onChange={e => set('email', e.target.value)} /></div>
                <div className="form-group"><label>Chủ đề</label><select value={form.subject} onChange={e => set('subject', e.target.value)}>{SUBJECTS.map(s => <option key={s}>{s}</option>)}</select></div>
              </div>
              <div className="form-group"><label>Nội dung *</label><textarea placeholder="Mô tả chi tiết vấn đề bạn gặp phải..." value={form.message} onChange={e => set('message', e.target.value)} rows={5} /></div>
              <button type="submit" className="btn btn-dark" style={{ width: '100%', justifyContent: 'center' }} disabled={loading}>
                {loading ? '⏳ Đang gửi...' : '📩 Gửi yêu cầu'}
              </button>
            </form>
          </div>
        </div>
      </div>
    </section>
  );
}
